  function requireSamePassword(passId, confirmId){ const p=norm($(passId)?.value); const c=norm($(confirmId)?.value); if(p.length<6) throw new Error('A senha precisa ter pelo menos 6 caracteres.'); if(p!==c) throw new Error('A confirmação de senha não confere.'); return p; }
  function splitTurmas(v){ if(Array.isArray(v)) return v.map(norm).filter(Boolean); return norm(v).split(/[;,|]/).map(norm).filter(Boolean); }

  function inferField(headers, candidates){
    const normalized = headers.map(h => ({raw:h, key:lower(h)}));
    for (const cand of candidates){ const c=lower(cand); const exact=normalized.find(h=>h.key===c); if(exact) return exact.raw; }
    for (const cand of candidates){ const c=lower(cand); const contains=normalized.find(h=>h.key.includes(c)||c.includes(h.key)); if(contains) return contains.raw; }
    return null;
  }

  function firstNonEmptyRowsToObjects(sheet, sheetName){
    const raw = XLSX.utils.sheet_to_json(sheet, {header:1, defval:'', blankrows:false});
    if(!raw.length) return {rows:[], headers:[], headerIndex:-1};
    let best={index:0, score:-1};
    for(let i=0;i<Math.min(raw.length,25);i++){
      const cells=raw[i].map(norm).filter(Boolean); const keys=cells.map(lower).join(' | '); let score=cells.length;
      ['aluno','nome','turma','serie','série','diagnostico','diagnóstico','laudo','adaptacao','adaptação','prova','atividade','necessidade'].forEach(k=>{ if(keys.includes(lower(k))) score+=7; });
      if(score>best.score) best={index:i, score};
    }
    const headers=raw[best.index].map((h,idx)=>norm(h)||`Coluna ${idx+1}`);
    const rows=[];
    for(let r=best.index+1;r<raw.length;r++){
      const arr=raw[r]; if(!arr || !arr.some(c=>norm(c))) continue;
      const obj={}; headers.forEach((h,i)=>{ obj[h]=norm(arr[i]); }); obj.__aba=sheetName; obj.__linha=r+1; rows.push(obj);
    }
    return {rows, headers, headerIndex:best.index};
  }

  async function readWorkbook(file){
    const data = await file.arrayBuffer();
    if(file.name && file.name.toLowerCase().endsWith('.csv')) return XLSX.read(new TextDecoder('utf-8').decode(data), {type:'string'});
    return XLSX.read(data, {type:'array'});
  }

  function extractMainFields(row, headers, sheetName){
    const fAluno = inferField(headers, ['nome do aluno','aluno','nome aluno','estudante','educando','discente','nome completo','nome']);
    const fTurma = inferField(headers, ['turma','série','serie','ano','classe','sala']);
    const fNum = inferField(headers, ['numero','número','nº','n']);
    const fDiag = inferField(headers, ['diagnostico','diagnóstico','laudo','cid','necessidade','deficiencia','deficiência','transtorno']);
    const fAdapt = inferField(headers, ['adaptacao','adaptação','tipo de adaptação','adaptacoes','adaptações','adequacao','adequação','prova adaptada']);
    const fTipo = inferField(headers, ['tipo de prova','prova','avaliação','avaliacao','atividade','instrumento']);
    const fOrient = inferField(headers, ['orientacao','orientação','sugestao','sugestão','observacao','observação','descricao','descrição','recomendação','recomendacao']);
    return {
      nome:norm(fAluno ? row[fAluno] : ''), turma:norm(fTurma ? row[fTurma] : ''), numero:norm(fNum ? row[fNum] : ''),
      diagnostico:norm(fDiag ? row[fDiag] : ''), adaptacao:norm(fAdapt ? row[fAdapt] : ''), tipoProva:norm(fTipo ? row[fTipo] : ''), orientacoes:norm(fOrient ? row[fOrient] : ''),
      abaOrigem:sheetName, dadosCompletos:row
    };
  }

