  function setupHamburgerMenus(){
    [
      {btn:'adminHamburger', backdrop:'adminMenuBackdrop'},
      {btn:'profHamburger', backdrop:'profMenuBackdrop'}
    ].forEach(cfg=>{
      const btn=$(cfg.btn);
      const backdrop=$(cfg.backdrop);
      if(!btn) return;

      const appView = btn.closest('.app');
      const sidebar = appView?.querySelector('.sidebar');
      if(!appView || !sidebar) return;

      const closeMenu = ()=>setHamburgerMenu(appView, sidebar, backdrop, btn, false);
      const toggleMenu = ()=>setHamburgerMenu(appView, sidebar, backdrop, btn, !sidebar.classList.contains('menu-open'));

      closeMenu();
      btn.addEventListener('click', toggleMenu);
      backdrop?.addEventListener('click', closeMenu);

      sidebar.querySelectorAll('nav a').forEach(link=>{
        link.addEventListener('click', ()=>{
          sidebar.querySelectorAll('nav a').forEach(a=>a.classList.remove('active'));
          link.classList.add('active');
          closeMenu();
        });
      });

      document.addEventListener('keydown', e=>{ if(e.key==='Escape') closeMenu(); });
      window.addEventListener('resize', closeMenu);
    });
  }

  function setHamburgerMenu(appView, sidebar, backdrop, btn, open){
    if(!sidebar) return;
    sidebar.classList.toggle('menu-open', !!open);
    appView?.classList.toggle('menu-open', !!open);
    backdrop?.classList.toggle('hidden', !open);
    btn?.setAttribute('aria-expanded', open?'true':'false');
  }

  function closeHamburgerMenu(appView){
    const sidebar=appView?.querySelector('.sidebar');
    const backdrop=appView?.querySelector('.menu-backdrop');
    const btn=appView?.querySelector('.hamburger-btn');
    setHamburgerMenu(appView, sidebar, backdrop, btn, false);
  }


