  function organizarConteudoParaIaLocal(texto){
    const bruto = norm(texto);
    const linhas = bruto.split(/\r?\n/).map(l=>l.trim()).filter(Boolean);
    const jaEstruturado = /tema\s*:|t[oó]picos?\s*:|objetivo\s*:|exemplos?\s*:|f[oó]rmulas?\s*:/i.test(bruto);
    if(jaEstruturado) return bruto;

    const frases = bruto
      .replace(/\s+/g,' ')
      .split(/(?<=[.!?])\s+|;\s+|\s+-\s+/)
      .map(s=>s.trim())
      .filter(s=>s.length>10);

    const topicos = linhas.length>1 ? linhas.map(l=>l.replace(/^[-*•\d.)]+\s*/,'').trim()).filter(l=>l.length>3) : frases.slice(0,10);
    const formulas = topicos.filter(t=>/[=+\-*/Δ²³]|\b\d+\s*\/\s*\d+\b|\b\d+(?:[,.]\d+)?\s*%/.test(t)).slice(0,6);
    const exemplos = topicos.filter(t=>/exemplo|por exemplo|como|situa[cç][aã]o|calcule|observe|\d/.test(lower(t))).slice(0,6);
    const temaProvavel = detectarTemaProvavelConteudo(bruto, topicos);

    return `Tema: ${temaProvavel}

Tópicos:
${topicos.slice(0,14).map(t=>`- ${t}`).join('\n')}

${formulas.length ? `Fórmulas/Dados importantes:\n${formulas.map(t=>`- ${t}`).join('\n')}\n\n` : ''}${exemplos.length ? `Exemplos:\n${exemplos.map(t=>`- ${t}`).join('\n')}\n\n` : ''}Objetivo da aula:
- Compreender os conceitos principais
- Aplicar o conteúdo em questões objetivas e discursivas
- Relacionar o tema com exemplos e situações-problema`;
  }

  function detectarTemaProvavelConteudo(bruto, topicos){
    const m = bruto.match(/(?:tema|assunto|conte[uú]do)\s*:\s*([^\n.;]{3,80})/i);
    if(m) return norm(m[1]);
    const first = topicos.find(t=>t.length>=4 && t.length<=80) || bruto.slice(0,60);
    return first.replace(/^[-*•\d.)]+\s*/,'').trim();
  }

