  function makeAlunoKey(main, seenKeys){
    const raw = `${main.nome || 'aluno'}_${main.turma || main.abaOrigem || 'sem_turma'}_${main.numero || main.__linha || ''}`;
    let base = lower(raw).replace(/[^a-z0-9]+/g,'_').replace(/^_+|_+$/g,'').slice(0,110) || uid();
    let key = base;
    let n = 2;
    while(seenKeys.has(key)){
      key = `${base}_${n++}`;
    }
    seenKeys.add(key);
    return key;
  }

  async function firebaseBatchUpdate(updates, batchSize){
    const entries = Object.entries(updates);
    for(let i=0;i<entries.length;i+=batchSize){
      const batch = Object.fromEntries(entries.slice(i, i+batchSize));
      await db.ref().update(batch);
    }
  }

  async function importarPlanilhaAlunos(file){
    const reportEl = $('importReport');
    if(reportEl) reportEl.textContent = 'Lendo planilha, validando registros e preparando envio...';

    try{
      if(!window.XLSX) throw new Error('Biblioteca XLSX não carregada. Verifique a internet e abra pelo servidor local.');

      const wb = await readWorkbook(file);
      const substituir = $('substituirAlunos')?.checked;
      const updates = {};
      const seenKeys = new Set();
      const turmaSet = new Set();
      const colSet = new Set();
      const reports = [];
      const warnings = [];
      let total = 0;
      let ignorados = 0;

      wb.SheetNames.forEach(sheetName=>{
        const parsed = firstNonEmptyRowsToObjects(wb.Sheets[sheetName], sheetName);
        let imported = 0;
        let skipped = 0;
        parsed.headers.forEach(h=>colSet.add(h));

        parsed.rows.forEach(row=>{
          parsed.headers.forEach(h=>colSet.add(h));
          const main = extractMainFields(row, parsed.headers, sheetName);
          main.__linha = row.__linha;
          main.__aba = sheetName;

          // Registro profissional: aluno sem nome não entra na base, para evitar linhas de título/rodapé.
          if(!main.nome){ skipped++; ignorados++; return; }
          if(!main.turma) main.turma = sheetName;
          if(main.turma) turmaSet.add(main.turma);

          const key = makeAlunoKey(main, seenKeys);
          updates['alunos/'+key] = {
            ...main,
            dadosCompletos: {...row},
            atualizadoEm: nowIso(),
            criadoEm: nowIso(),
            origemImportacao: {
              arquivo: file.name || 'planilha',
              aba: sheetName,
              linha: row.__linha || null
            }
          };
          imported++;
          total++;
        });

        reports.push(`Aba: ${sheetName} | cabeçalho linha: ${parsed.headerIndex+1} | importados: ${imported} | ignorados sem nome: ${skipped} | colunas: ${parsed.headers.length}`);
      });

      if(!total) throw new Error('Nenhum aluno válido foi encontrado. Confira se a planilha possui uma coluna de nome do aluno.');

      // Correção principal: não envia /alunos = null junto com /alunos/id no mesmo update,
      // pois o Firebase rejeita caminhos ancestrais e filhos na mesma operação.
      if(substituir){
        if(reportEl) reportEl.textContent = 'Substituindo base anterior...';
        await db.ref('alunos').remove();
      }

      if(reportEl) reportEl.textContent = `Enviando ${total} aluno(s) em lotes seguros...`;
      await firebaseBatchUpdate(updates, 250);

      await audit('importar_alunos', {
        arquivo:file.name || 'planilha',
        total,
        ignorados,
        substituir,
        abas:wb.SheetNames.length,
        turmas:Array.from(turmaSet)
      });

      if(reportEl){
        reportEl.textContent = `Importação concluída com sucesso.\n`+
          `Total de alunos importados: ${total}\n`+
          `Linhas ignoradas sem nome: ${ignorados}\n`+
          `Turmas encontradas: ${Array.from(turmaSet).join(', ') || 'nenhuma'}\n`+
          `Colunas preservadas: ${colSet.size}\n`+
          `Modo: ${substituir ? 'base anterior substituída antes da importação' : 'registros adicionados/atualizados'}\n\n`+
          reports.join('\n')+
          (warnings.length ? `\n\nAvisos:\n${warnings.join('\n')}` : '');
      }
    }catch(error){
      if(reportEl) reportEl.textContent = 'Erro ao importar: '+firebaseError(error);
    }
  }

