  function dadoContextualEM(analise, i){
    return analise.frasesRelevantes[(i-1) % analise.frasesRelevantes.length] || analise.resumo || analise.bruto.slice(0,260);
  }

  function conceitoEM(analise, i){
    return formatarConceitoEM(analise.conceitos[(i-1) % analise.conceitos.length] || analise.topicos[(i-1)%analise.topicos.length]?.label || analise.tema);
  }

  function montarQuestaoFracaoEM(ctx){
    const f = ctx.analise.numeros.fracoes[(ctx.i-1)%ctx.analise.numeros.fracoes.length] || ['1/2','2/4','3/4','2/7','3/7','5/8','7/4'][(ctx.i-1)%7];
    const modelos=[
      {title:`Observe a fração ${f}. Explique o que representam o numerador e o denominador.`, hint:'Numerador indica as partes consideradas; denominador indica em quantas partes iguais o inteiro foi dividido.', options:[`A) O número de cima indica as partes consideradas e o de baixo indica as partes iguais do inteiro.`,`B) O denominador sempre representa a resposta final de uma conta.`,`C) O numerador indica o total de inteiros completos.`,`D) Frações não representam partes de um inteiro.`]},
      {title:'Qual é a ideia principal de frações equivalentes?', hint:'Frações equivalentes representam a mesma quantidade.', options:[`A) São frações diferentes que representam a mesma parte do inteiro.`,`B) São frações que sempre possuem o mesmo numerador.`,`C) São frações que não podem ser comparadas.`,`D) São frações usadas apenas em números decimais.`]},
      {title:'Resolva: 2/7 + 3/7.', hint:'Com denominadores iguais, mantenha o denominador e some os numeradores.', options:[`A) 5/7`,`B) 5/14`,`C) 6/7`,`D) 1/7`]},
      {title:'Compare 3/5 e 2/5. Qual fração é maior?', hint:'Com denominadores iguais, compare os numeradores.', options:[`A) 3/5`,`B) 2/5`,`C) As duas são iguais a zero.`,`D) Não é possível comparar.`]},
      {title:'Diferencie fração própria e fração imprópria usando exemplos.', hint:'Compare o numerador com o denominador.', options:[`A) Própria tem numerador menor que denominador; imprópria tem numerador maior ou igual ao denominador.`,`B) Própria não possui denominador.`,`C) Imprópria sempre vale menos que uma unidade.`,`D) Não há diferença entre elas.`]}
    ];
    return montarDeModeloEM(ctx, modelos);
  }

