  function montarQuestaoMatematicaGeralEM(ctx){ return montarQuestaoAreaEM(ctx, bancoAreaEM().matematica); }
  function montarQuestaoPortuguesGeralEM(ctx){ return montarQuestaoAreaEM(ctx, bancoAreaEM().portugues); }
